// Proves ifft2(fft2(x)) round-trips real-input planes within 1e-6 RMSE on
// power-of-2 dims (16/32/64) and that imaginary leakage stays near zero.
// This is the gating test before Wiener deblur is wired against fft2.ts —
// if this is red, the deblur smoke (256x256 fixture) cannot be trusted.

import { describe, it, expect } from 'vitest';
import { fft2, ifft2, ifft2Complex, isPowerOfTwo } from '../src/fft2';

function rmse(a: Float32Array, b: Float32Array): number {
  let s = 0;
  for (let i = 0; i < a.length; i++) { const d = a[i]! - b[i]!; s += d * d; }
  return Math.sqrt(s / a.length);
}

describe('fft2 round-trip', () => {
  it('zeros 16x16 round-trip is zero within 1e-12', () => {
    const w = 16, h = 16;
    const x = new Float32Array(w * h);
    const back = ifft2(fft2(x, w, h));
    expect(rmse(x, back)).toBeLessThan(1e-12);
  });

  it('64x64 deterministic ramp round-trips within 1e-6 RMSE', () => {
    const w = 64, h = 64;
    const x = new Float32Array(w * h);
    for (let y = 0; y < h; y++) {
      for (let xi = 0; xi < w; xi++) {
        x[y * w + xi] = (xi + y) / 128;
      }
    }
    const back = ifft2(fft2(x, w, h));
    expect(rmse(x, back)).toBeLessThan(1e-6);
  });

  it('32x32 seeded LCG random round-trips within 1e-6 RMSE', () => {
    const w = 32, h = 32;
    let s = 1;
    const rand = () => { s = (s * 1103515245 + 12345) & 0x7fffffff; return s / 0x7fffffff; };
    const x = new Float32Array(w * h);
    for (let i = 0; i < x.length; i++) x[i] = rand();
    const back = ifft2(fft2(x, w, h));
    expect(rmse(x, back)).toBeLessThan(1e-6);
  });

  it('32x32 real-input ifft2Complex has near-zero imaginary leakage', () => {
    const w = 32, h = 32;
    let s = 1;
    const rand = () => { s = (s * 1103515245 + 12345) & 0x7fffffff; return s / 0x7fffffff; };
    const x = new Float32Array(w * h);
    for (let i = 0; i < x.length; i++) x[i] = rand();
    const back = ifft2Complex(fft2(x, w, h));
    let maxIm = 0;
    for (let i = 0; i < back.im.length; i++) {
      const v = Math.abs(back.im[i]!);
      if (v > maxIm) maxIm = v;
    }
    expect(maxIm).toBeLessThan(1e-6);
  });

  it('isPowerOfTwo direct asserts', () => {
    expect(isPowerOfTwo(256)).toBe(true);
    expect(isPowerOfTwo(255)).toBe(false);
    expect(isPowerOfTwo(1)).toBe(true);
    expect(isPowerOfTwo(0)).toBe(false);
  });
});
